const projects = [{
  name: 'Project Name',
  link: '#',
  lang: 'Python',
  imageURL: require('./assets/myman.png'),
  desc: 'Lorem ipsum dolor sit amet, officia excepteur ex fugiat reprehenderit enim labore culpa sint ad nisi Lorem pariatur mollit ex esse exercitation amet. Nisi anim cupidatat excepteur officia. Reprehenderit nostrud nostrud ipsum Lorem est aliquip amet voluptate voluptate dolor minim nulla est proident. Nostrud officia pariatur ut officia. Sit irure elit esse ea nulla sunt ex occaecat reprehenderit commodo officia dolor Lorem duis laboris cupidatat officia voluptate. Culpa proident adipisicing id nulla nisi laboris ex in Lorem sunt duis officia eiusmod. Aliqua reprehenderit commodo ex non excepteur duis sunt velit enim. Voluptate laboris sint cupidatat ullamco ut ea consectetur et est culpa et culpa duis.'
}, {
  name: 'Project Name',
  link: '#',
  lang: 'Python',
  imageURL: null,
  desc: 'Lorem ipsum dolor sit amet, officia excepteur ex fugiat reprehenderit enim labore culpa sint ad nisi Lorem pariatur mollit ex esse exercitation amet. Nisi anim cupidatat excepteur officia. Reprehenderit nostrud nostrud ipsum Lorem est aliquip amet voluptate voluptate dolor minim nulla est proident. Nostrud officia pariatur ut officia. Sit irure elit esse ea nulla sunt ex occaecat reprehenderit commodo officia dolor Lorem duis laboris cupidatat officia voluptate. Culpa proident adipisicing id nulla nisi laboris ex in Lorem sunt duis officia eiusmod. Aliqua reprehenderit commodo ex non excepteur duis sunt velit enim.'
}];



function ProjectDescription({ name, link, lang, desc, children }) {
    return (
      <a href={ link } className='rounded-md p-4 bg-gunmetal hover:bg-gunmetal-light flex flex-row space-x-4 content-center'>
        <div className='basis-auto flex flex-col'>
          <h1 className='text-xl text-stone-200 font-[DrukWide]'> { name } </h1>
          <p className='text-md text-stone-200 font-[DrukWide] pb-4'> { lang } </p>
          <p> { desc } </p>
        </div>
        <div className='basis-auto flex flex-col'>
          { children }
        </div>
      </a>
    );
}

function Project({ name, link, lang, imageURL, desc }) {
  if (imageURL === null) {
    return (
      <ProjectDescription name={ name } link={ link } lang={ lang } desc={ desc } />
    );
  } else {
    return (
      <ProjectDescription name={ name } link={ link } lang={ lang } desc={ desc }>
        <img src={ imageURL } alt={ 'Image of ' + name } />
      </ProjectDescription>
    );
  }
}

function Projects() {
  const projectItems = projects.map(project => 
  <li className='py-3'>
    <Project name={project.name} 
    link={project.link} 
    lang={project.lang}
    imageURL={project.imageURL} 
    desc={project.desc}/>
  </li>
  );

  return (
    <>
      <h1 className='text-3xl text-center text-stone-200 font-[DrukWide]'>
        Recent Projects
      </h1>
      <ul>
        { projectItems }
      </ul>
    </>
  );
}

export default Projects;
